   160Ôćĺ// docPath strips the /v1/<dbname> prefix from a full path,
   161Ôćĺ// returning just the document path (e.g., "/Workspace/channels/General").
   162Ôćĺ// P2 (m3ssag1n8) expects paths without the database prefix.
   163Ôćĺfunc docPath(fullPath string) string {
   164Ôćĺ	// fullPath looks like /v1/dbname/... or /v1/dbname
   165Ôćĺ	p := strings.TrimPrefix(fullPath, "/v1/")
   166Ôćĺ	if idx := strings.Index(p, "/"); idx >= 0 {
   167Ôćĺ		return p[idx:]
   168Ôćĺ	}
   169Ôćĺ	return "/"
   170Ôćĺ}
