   172Ôćĺfunc (h *Handler) handleV1(w http.ResponseWriter, r *http.Request, username string) {
   173Ôćĺ	rawPath := strings.TrimPrefix(r.URL.Path, "/v1/")
   174Ôćĺ	if rawPath == "" || rawPath == "/" {
   175Ôćĺ		writeError(w, http.StatusBadRequest, "empty path")
   176Ôćĺ		return
   177Ôćĺ	}
   178Ôćĺ
   179Ôćĺ	isCollection := strings.HasSuffix(rawPath, "/")
   180Ôćĺ	mode := r.URL.Query().Get("mode")
   181Ôćĺ
   182Ôćĺ	// Handle subscribe mode
   183Ôćĺ	if mode == "subscribe" {
   184Ôćĺ		h.handleSubscribe(w, r, rawPath, username)
   185Ôćĺ		return
   186Ôćĺ	}
   187Ôćĺ
   188Ôćĺ	switch r.Method {
   189Ôćĺ	case http.MethodGet:
   190Ôćĺ		h.handleGet(w, r, rawPath, isCollection, username)
   191Ôćĺ	case http.MethodPut:
   192Ôćĺ		h.handlePut(w, r, rawPath, isCollection, mode, username)
   193Ôćĺ	case http.MethodPost:
   194Ôćĺ		h.handlePost(w, r, rawPath, isCollection, username)
   195Ôćĺ	case http.MethodDelete:
   196Ôćĺ		h.handleDelete(w, r, rawPath, isCollection, username)
   197Ôćĺ	case http.MethodPatch:
   198Ôćĺ		h.handlePatch(w, r, rawPath, username)
   199Ôćĺ	default:
   200Ôćĺ		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
   201Ôćĺ	}
   202Ôćĺ}
