   204Ôćĺfunc (h *Handler) handleGet(w http.ResponseWriter, r *http.Request, rawPath string, isCollection bool, username string) {
   205Ôćĺ	cleanPath := strings.Trim(rawPath, "/")
   206Ôćĺ	parts := splitAndDecode(cleanPath)
   207Ôćĺ
   208Ôćĺ	if len(parts) == 0 {
   209Ôćĺ		writeError(w, http.StatusBadRequest, "empty path")
   210Ôćĺ		return
   211Ôćĺ	}
   212Ôćĺ
   213Ôćĺ	dbName := parts[0]
   214Ôćĺ	dbCol, exists := h.dbm.GetDatabase(dbName)
   215Ôćĺ	if !exists {
   216Ôćĺ		writeError(w, http.StatusNotFound, "database not found")
   217Ôćĺ		return
   218Ôćĺ	}
   219Ôćĺ
   220Ôćĺ	// Database-level GET (collection of top-level docs)
   221Ôćĺ	if len(parts) == 1 {
   222Ôćĺ		intervalStr := r.URL.Query().Get("interval")
   223Ôćĺ		h.getCollection(w, dbCol, "/v1/"+dbName, intervalStr)
   224Ôćĺ		return
   225Ôćĺ	}
   226Ôćĺ
   227Ôćĺ	// Navigate to target
   228Ôćĺ	col, doc, docName, colPath, err := h.navigatePath(dbCol, parts[1:], "/v1/"+dbName)
   229Ôćĺ	if err != nil {
   230Ôćĺ		writeError(w, http.StatusNotFound, err.Error())
   231Ôćĺ		return
   232Ôćĺ	}
   233Ôćĺ
   234Ôćĺ	if isCollection {
   235Ôćĺ		if col == nil {
   236Ôćĺ			writeError(w, http.StatusNotFound, "collection not found")
   237Ôćĺ			return
   238Ôćĺ		}
   239Ôćĺ		intervalStr := r.URL.Query().Get("interval")
   240Ôćĺ		h.getCollection(w, col, colPath, intervalStr)
   241Ôćĺ		return
   242Ôćĺ	}
   243Ôćĺ
   244Ôćĺ	if doc == nil {
   245Ôćĺ		writeError(w, http.StatusNotFound, "document not found")
   246Ôćĺ		return
   247Ôćĺ	}
   248Ôćĺ
   249Ôćĺ	resp, err := doc.ToResponse("/v1/" + cleanPath)
   250Ôćĺ	if err != nil {
   251Ôćĺ		writeError(w, http.StatusInternalServerError, err.Error())
   252Ôćĺ		return
   253Ôćĺ	}
   254Ôćĺ	_ = docName
   255Ôćĺ	writeJSON(w, http.StatusOK, resp)
   256Ôćĺ}
