   258Ôćĺfunc (h *Handler) getCollection(w http.ResponseWriter, col *db.Collection, basePath string, intervalStr string) {
   259Ôćĺ	low, high, lowInc, highInc := parseInterval(intervalStr)
   260Ôćĺ	docs := col.ListDocuments(low, high, lowInc, highInc)
   261Ôćĺ
   262Ôćĺ	result := make([]db.DocumentResponse, 0, len(docs))
   263Ôćĺ	for _, d := range docs {
   264Ôćĺ		docPath := basePath + "/" + d.Name
   265Ôćĺ		// Trim any double slashes
   266Ôćĺ		docPath = strings.ReplaceAll(docPath, "//", "/")
   267Ôćĺ		resp, err := d.Doc.ToResponse(docPath)
   268Ôćĺ		if err != nil {
   269Ôćĺ			continue
   270Ôćĺ		}
   271Ôćĺ		result = append(result, resp)
   272Ôćĺ	}
   273Ôćĺ
   274Ôćĺ	writeJSON(w, http.StatusOK, result)
   275Ôćĺ}
