   277Ôćĺfunc (h *Handler) handlePut(w http.ResponseWriter, r *http.Request, rawPath string, isCollection bool, mode string, username string) {
   278Ôćĺ	cleanPath := strings.Trim(rawPath, "/")
   279Ôćĺ	parts := splitAndDecode(cleanPath)
   280Ôćĺ
   281Ôćĺ	if len(parts) == 0 {
   282Ôćĺ		writeError(w, http.StatusBadRequest, "empty path")
   283Ôćĺ		return
   284Ôćĺ	}
   285Ôćĺ
   286Ôćĺ	dbName := parts[0]
   287Ôćĺ
   288Ôćĺ	// Creating a database (path is just the db name with trailing slash)
   289Ôćĺ	if len(parts) == 1 && isCollection {
   290Ôćĺ		_, err := h.dbm.CreateDatabase(dbName)
   291Ôćĺ		if err != nil {
   292Ôćĺ			writeError(w, http.StatusConflict, "database already exists")
   293Ôćĺ			return
   294Ôćĺ		}
   295Ôćĺ		// Database-level URI keeps the full /v1/<dbname> path
   296Ôćĺ		writeJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbName})
   297Ôćĺ		return
   298Ôćĺ	}
   299Ôćĺ
   300Ôćĺ	// For non-collection PUT, we need a database and document path
   301Ôćĺ	if len(parts) == 1 && !isCollection {
   302Ôćĺ		// PUT /v1/dbname without trailing slash - try creating database
   303Ôćĺ		_, err := h.dbm.CreateDatabase(dbName)
   304Ôćĺ		if err != nil {
   305Ôćĺ			writeError(w, http.StatusConflict, "database already exists")
   306Ôćĺ			return
   307Ôćĺ		}
   308Ôćĺ		writeJSON(w, http.StatusCreated, map[string]string{"uri": "/v1/" + dbName})
   309Ôćĺ		return
   310Ôćĺ	}
   311Ôćĺ
   312Ôćĺ	dbCol, exists := h.dbm.GetDatabase(dbName)
   313Ôćĺ	if !exists {
   314Ôćĺ		writeError(w, http.StatusNotFound, "database not found")
   315Ôćĺ		return
   316Ôćĺ	}
   317Ôćĺ
   318Ôćĺ	// Creating a collection (trailing slash, even number of remaining segments means collection)
   319Ôćĺ	if isCollection && len(parts) >= 3 && len(parts)%2 == 1 {
   320Ôćĺ		// e.g., /v1/db/doc1/col1/ -> parts = [db, doc1, col1]
   321Ôćĺ		// Navigate to parent doc, create collection
   322Ôćĺ		parentParts := parts[1 : len(parts)-1]
   323Ôćĺ		colName := parts[len(parts)-1]
   324Ôćĺ
   325Ôćĺ		parentCol := dbCol
   326Ôćĺ		var parentDoc *db.Document
   327Ôćĺ
   328Ôćĺ		for i := 0; i < len(parentParts); i++ {
   329Ôćĺ			if i%2 == 0 {
   330Ôćĺ				// Document
   331Ôćĺ				d, ok := parentCol.GetDocument(parentParts[i])
   332Ôćĺ				if !ok {
   333Ôćĺ					writeError(w, http.StatusNotFound, "parent document not found")
   334Ôćĺ					return
   335Ôćĺ				}
   336Ôćĺ				parentDoc = d
   337Ôćĺ			} else {
   338Ôćĺ				// Collection
   339Ôćĺ				c, ok := parentDoc.GetCollection(parentParts[i])
   340Ôćĺ				if !ok {
   341Ôćĺ					writeError(w, http.StatusNotFound, "parent collection not found")
   342Ôćĺ					return
   343Ôćĺ				}
   344Ôćĺ				parentCol = c
   345Ôćĺ			}
   346Ôćĺ		}
