import { fetchEventSource } from "@microsoft/fetch-event-source";
import { slog } from "./slog";

/**
 * Declare names and types of environment variables.
 */
declare const process: {
  env: {
    DATABASE_HOST: string;
    DATABASE_PATH: string;
    AUTH_PATH: string;
  };
};

// ============================================================================
// Types
// ============================================================================

interface Metadata {
  createdBy: string;
  createdAt: number;
  lastModifiedBy: string;
  lastModifiedAt: number;
}

interface PostDoc {
  msg: string;
  parent: string;
  reactions?: Record<string, string[]>;
}

interface DocumentResponse {
  path: string;
  doc: unknown;
  meta: Metadata;
}

interface PostRecord {
  path: string;
  doc: PostDoc;
  meta: Metadata;
  depth: number;
}

// ============================================================================
// State
// ============================================================================

let authToken: string | null = null;
let currentUsername: string | null = null;
let currentWorkspace: string | null = null;
let currentChannel: string | null = null;
let sseAbortController: AbortController | null = null;

// Map from post path to post record (for live update merging)
const postsMap = new Map<string, PostRecord>();

// ============================================================================
// Config
// ============================================================================

const DB_HOST = process.env.DATABASE_HOST;
const DB_PATH = process.env.DATABASE_PATH;
const AUTH_PATH = process.env.AUTH_PATH;

function dbUrl(path: string): string {
  // path is the path relative to the database (after DB_PATH)
  return `${DB_HOST}${DB_PATH}${path}`;
}

function authUrl(): string {
  return `${DB_HOST}${AUTH_PATH}`;
}

// ============================================================================
// Notification / Error display
// ============================================================================

function showNotification(message: string): void {
  const notif = document.getElementById("notification")!;
  const msg = document.getElementById("notification-message")!;
  msg.textContent = message;
  notif.style.display = "flex";
  // Auto-hide after 5 seconds
  setTimeout(() => {
    notif.style.display = "none";
  }, 5000);
}

function hideNotification(): void {
  const notif = document.getElementById("notification")!;
  notif.style.display = "none";
}

// ============================================================================
// Auth API
// ============================================================================

async function apiLogin(username: string): Promise<string | null> {
  try {
    const resp = await fetch(authUrl(), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ username }),
    });
    if (!resp.ok) {
      const err = await resp.text();
      showNotification(`Login failed: ${err}`);
      return null;
    }
    const data = (await resp.json()) as { token: string };
    return data.token;
  } catch (e) {
    showNotification(`Login error: ${e}`);
    return null;
  }
}

async function apiLogout(): Promise<void> {
  if (!authToken) return;
  try {
    await fetch(authUrl(), {
      method: "DELETE",
      headers: { Authorization: `Bearer ${authToken}` },
    });
  } catch (e) {
    slog.warn("Logout error", ["error", e]);
  }
}

// ============================================================================
// Generic fetch helper
// ============================================================================

async function apiFetch(
  url: string,
  options: RequestInit = {}
): Promise<Response> {
  const headers: Record<string, string> = {
    "Content-Type": "application/json",
    ...(options.headers as Record<string, string>),
  };
  if (authToken) {
    headers["Authorization"] = `Bearer ${authToken}`;
  }
  return fetch(url, { ...options, headers });
}

// ============================================================================
// Workspace API
// ============================================================================

async function fetchWorkspaces(): Promise<DocumentResponse[]> {
  const resp = await apiFetch(dbUrl(""));
  if (!resp.ok) return [];
  return (await resp.json()) as DocumentResponse[];
}

async function createWorkspace(name: string): Promise<boolean> {
  // Create workspace document
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(name)}`,
    { method: "PUT", body: JSON.stringify({}) }
  );
  if (!resp.ok) {
    if (resp.status === 409) {
      showNotification(`Error: Workspace "${name}" already exists`);
    } else {
      const err = await resp.text();
      showNotification(`Error creating workspace: ${err}`);
    }
    return false;
  }
  // Create channels collection
  await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(name)}/channels/`,
    { method: "PUT" }
  );
  return true;
}

async function deleteWorkspaceApi(name: string): Promise<boolean> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(name)}`,
    { method: "DELETE" }
  );
  if (!resp.ok) {
    if (resp.status === 404) {
      showNotification(`Error: Workspace "${name}" not found`);
    } else {
      const err = await resp.text();
      showNotification(`Error deleting workspace: ${err}`);
    }
    return false;
  }
  return true;
}

async function fetchChannels(workspace: string): Promise<DocumentResponse[]> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/`
  );
  if (!resp.ok) return [];
  return (await resp.json()) as DocumentResponse[];
}

async function createChannel(workspace: string, name: string): Promise<boolean> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    { method: "PUT", body: JSON.stringify({}) }
  );
  if (!resp.ok) {
    if (resp.status === 409) {
      showNotification(`Error: Channel "${name}" already exists`);
    } else {
      const err = await resp.text();
      showNotification(`Error creating channel: ${err}`);
    }
    return false;
  }
  // Create posts collection
  await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}/posts/`,
    { method: "PUT" }
  );
  return true;
}

async function deleteChannelApi(workspace: string, name: string): Promise<boolean> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(name)}`,
    { method: "DELETE" }
  );
  if (!resp.ok) {
    if (resp.status === 404) {
      showNotification(`Error: Channel "${name}" not found`);
    } else {
      const err = await resp.text();
      showNotification(`Error deleting channel: ${err}`);
    }
    return false;
  }
  return true;
}

async function createPost(
  workspace: string,
  channel: string,
  msg: string,
  parent: string = ""
): Promise<string | null> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`,
    { method: "POST", body: JSON.stringify({ msg, parent }) }
  );
  if (!resp.ok) {
    const err = await resp.text();
    showNotification(`Error creating post: ${err}`);
    return null;
  }
  const data = (await resp.json()) as { uri: string };
  return data.uri;
}

async function patchReactions(
  postPath: string,
  emoji: string,
  username: string,
  remove: boolean
): Promise<boolean> {
  const patches = [
    { op: "ObjectAdd", path: "/reactions", value: {} },
    { op: "ObjectAdd", path: `/reactions/${emoji}`, value: [] as string[] },
    {
      op: remove ? "ArrayRemove" : "ArrayAdd",
      path: `/reactions/${emoji}`,
      value: username,
    },
  ];
  // postPath is like "/WorkspaceName/channels/ChannelName/posts/postId"
  // The full API URL is DB_HOST + DB_PATH + postPath.substring(1)
  const url = `${DB_HOST}${DB_PATH}${postPath.substring(1)}`;
  const resp = await apiFetch(url, {
    method: "PATCH",
    body: JSON.stringify(patches),
  });
  if (!resp.ok) {
    slog.warn("Patch reaction failed", ["status", resp.status]);
    return false;
  }
  return true;
}

// ============================================================================
// Markdown Formatting
// ============================================================================

const EMOJI_MAP: Record<string, string> = {
  ":smile:": "­čśŐ",
  ":frown:": "Ôś╣´ŞĆ",
  ":like:": "­čĹŹ",
  ":celebrate:": "­čÄë",
  ":heart:": "ÔŁĄ´ŞĆ",
  ":thumbsup:": "­čĹŹ",
};

function formatMessage(text: string): HTMLElement {
  const container = document.createElement("span");
  // Process text line by line for newlines
  const lines = text.split("\n");
  lines.forEach((line, i) => {
    const lineSpan = document.createElement("span");
    lineSpan.innerHTML = formatLine(line);
    container.appendChild(lineSpan);
    if (i < lines.length - 1) {
      container.appendChild(document.createElement("br"));
    }
  });
  return container;
}

function formatLine(text: string): string {
  // Escape HTML first to prevent XSS
  let result = escapeHtml(text);

  // Bold: **text**
  result = result.replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>");

  // Italic: *text*
  result = result.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, "<em>$1</em>");

  // Links: [text](url)
  result = result.replace(
    /\[([^\]]+)\]\(([^)]+)\)/g,
    (_, displayText, url) => {
      const safeUrl = escapeHtml(url);
      return `<a href="${safeUrl}" target="_blank" rel="noopener noreferrer">${displayText}</a>`;
    }
  );

  // Emojis: :smile: etc.
  result = result.replace(/:[a-z_]+:/g, (match) => {
    const emoji = EMOJI_MAP[match];
    if (emoji) {
      return `<span class="emoji" title="${match}">${emoji}</span>`;
    }
    return match;
  });

  return result;
}

function escapeHtml(text: string): string {
  const div = document.createElement("div");
  div.appendChild(document.createTextNode(text));
  return div.innerHTML;
}

// ============================================================================
// Post Rendering
// ============================================================================

function getNameFromPath(path: string): string {
  // path is like "/WorkspaceName" or "/WorkspaceName/channels/ChannelName"
  // Return the last non-empty segment
  const parts = path.split("/").filter((p) => p.length > 0);
  return parts[parts.length - 1] || path;
}

function formatTime(timestampMs: number): string {
  const date = new Date(timestampMs);
  return date.toLocaleTimeString([], { hour: "2-digit", minute: "2-digit" });
}

function buildPostTree(posts: PostRecord[]): PostRecord[] {
  // Sort all posts by createdAt
  const sortedPosts = [...posts].sort(
    (a, b) => a.meta.createdAt - b.meta.createdAt
  );

  // Build children map: parent path Ôćĺ children
  const childrenMap = new Map<string, PostRecord[]>();
  const rootPosts: PostRecord[] = [];

  for (const post of sortedPosts) {
    const parent = post.doc.parent || "";
    if (!parent) {
      rootPosts.push(post);
    } else {
      if (!childrenMap.has(parent)) {
        childrenMap.set(parent, []);
      }
      childrenMap.get(parent)!.push(post);
    }
  }

  // DFS traversal to build ordered list with depths
  const result: PostRecord[] = [];

  function dfs(post: PostRecord, depth: number): void {
    result.push({ ...post, depth });
    const children = childrenMap.get(post.path) || [];
    // Children already sorted since we sorted all posts
    for (const child of children) {
      dfs(child, depth + 1);
    }
  }

  for (const root of rootPosts) {
    dfs(root, 0);
  }

  return result;
}

function renderPostElement(post: PostRecord): HTMLElement {
  const div = document.createElement("div");
  div.className = "post";
  div.dataset.path = post.path;
  div.style.marginLeft = `${post.depth * 20}px`;

  // Post meta (author + time)
  const meta = document.createElement("div");
  meta.className = "post-meta";

  const author = document.createElement("span");
  author.className = "post-author";
  author.textContent = post.meta.createdBy;
  meta.appendChild(author);

  const time = document.createElement("span");
  time.className = "post-time";
  time.textContent = formatTime(post.meta.createdAt);
  meta.appendChild(time);

  div.appendChild(meta);

  // Post content
  const content = document.createElement("div");
  content.className = "post-content";
  try {
    content.appendChild(formatMessage(post.doc.msg));
  } catch {
    content.textContent = post.doc.msg;
  }
  div.appendChild(content);

  // Post actions
  const actions = document.createElement("div");
  actions.className = "post-actions";

  // Reply button
  const replyBtn = document.createElement("button");
  replyBtn.className = "reply-btn";
  replyBtn.textContent = "Reply";
  replyBtn.addEventListener("click", () => toggleReplyComposer(post, div));
  actions.appendChild(replyBtn);

  // Reaction buttons
  const reactions: Array<{ emoji: string; icon: string }> = [
    { emoji: ":smile:", icon: "­čśŐ" },
    { emoji: ":frown:", icon: "Ôś╣´ŞĆ" },
    { emoji: ":like:", icon: "­čĹŹ" },
    { emoji: ":celebrate:", icon: "­čÄë" },
  ];

  for (const r of reactions) {
    const btn = document.createElement("button");
    btn.className = "react-btn";
    btn.dataset.reaction = r.emoji;

    const iconSpan = document.createElement("span");
    iconSpan.textContent = r.icon;
    btn.appendChild(iconSpan);

    const countSpan = document.createElement("span");
    countSpan.className = "react-count";
    const currentReactions = post.doc.reactions || {};
    const count = (currentReactions[r.emoji] || []).length;
    countSpan.textContent = count > 0 ? String(count) : "";
    if (count > 0) {
      countSpan.style.display = "inline";
    } else {
      countSpan.style.display = "none";
    }
    btn.appendChild(countSpan);

    // Highlight if current user has reacted
    if (
      currentUsername &&
      (currentReactions[r.emoji] || []).includes(currentUsername)
    ) {
      btn.classList.add("reacted");
    }

    btn.addEventListener("click", () => handleReaction(post, r.emoji, btn));
    actions.appendChild(btn);
  }

  div.appendChild(actions);

  // Reply composer (hidden by default)
  const replyComposer = document.createElement("div");
  replyComposer.className = "reply-composer";
  replyComposer.style.display = "none";

  const replyInput = document.createElement("textarea");
  replyInput.className = "reply-input";
  replyInput.placeholder = "Write a reply...";
  replyInput.rows = 2;
  replyComposer.appendChild(replyInput);

  const sendReplyBtn = document.createElement("button");
  sendReplyBtn.className = "send-reply-btn";
  sendReplyBtn.textContent = "Send Reply";
  sendReplyBtn.addEventListener("click", () =>
    handleSendReply(post, replyInput)
  );
  replyComposer.appendChild(sendReplyBtn);

  div.appendChild(replyComposer);

  return div;
}

function toggleReplyComposer(post: PostRecord, postEl: HTMLElement): void {
  const composer = postEl.querySelector(".reply-composer") as HTMLElement;
  if (!composer) return;
  if (composer.style.display === "none") {
    composer.style.display = "block";
    (composer.querySelector(".reply-input") as HTMLTextAreaElement)?.focus();
  } else {
    composer.style.display = "none";
  }
}

async function handleReaction(
  post: PostRecord,
  emoji: string,
  btn: HTMLButtonElement
): Promise<void> {
  if (!currentUsername) return;

  const currentReactions = post.doc.reactions || {};
  const reactors = currentReactions[emoji] || [];
  const alreadyReacted = reactors.includes(currentUsername);

  const success = await patchReactions(
    post.path,
    emoji,
    currentUsername,
    alreadyReacted
  );

  if (success) {
    // Optimistic update
    if (!post.doc.reactions) post.doc.reactions = {};
    if (!post.doc.reactions[emoji]) post.doc.reactions[emoji] = [];
    if (alreadyReacted) {
      post.doc.reactions[emoji] = post.doc.reactions[emoji].filter(
        (u) => u !== currentUsername
      );
      btn.classList.remove("reacted");
    } else {
      post.doc.reactions[emoji].push(currentUsername!);
      btn.classList.add("reacted");
    }
    // Update count display
    const countSpan = btn.querySelector(".react-count") as HTMLElement;
    if (countSpan) {
      const newCount = post.doc.reactions[emoji].length;
      countSpan.textContent = newCount > 0 ? String(newCount) : "";
      countSpan.style.display = newCount > 0 ? "inline" : "none";
    }
  }
}

async function handleSendReply(
  parentPost: PostRecord,
  input: HTMLTextAreaElement
): Promise<void> {
  const msg = input.value.trim();
  if (!msg || !currentWorkspace || !currentChannel) return;

  const uri = await createPost(
    currentWorkspace,
    currentChannel,
    msg,
    parentPost.path
  );
  if (uri) {
    input.value = "";
    // Close reply composer
    const composer = input.parentElement;
    if (composer) composer.style.display = "none";
    // SSE will update the post list
    // But also reload just in case
    await loadPosts(currentWorkspace, currentChannel);
  }
}

// ============================================================================
// Post List Rendering
// ============================================================================

function renderPostList(posts: PostRecord[]): void {
  const postList = document.getElementById("post-list")!;
  const ordered = buildPostTree(posts);

  // Save scroll position and input states before re-render
  const scrollTop = postList.scrollTop;
  const postInputEl = document.getElementById("post-input") as HTMLTextAreaElement;
  const savedPostInput = postInputEl ? postInputEl.value : "";

  // Save reply input states
  const replyInputs = new Map<string, string>();
  postList.querySelectorAll(".post").forEach((postEl) => {
    const path = (postEl as HTMLElement).dataset.path;
    const replyInput = postEl.querySelector(".reply-input") as HTMLTextAreaElement;
    if (path && replyInput && replyInput.value) {
      replyInputs.set(path, replyInput.value);
    }
  });

  // Re-render posts
  postList.innerHTML = "";
  for (const post of ordered) {
    const el = renderPostElement(post);
    postList.appendChild(el);

    // Restore reply input if it was open
    const savedReply = replyInputs.get(post.path);
    if (savedReply !== undefined) {
      const replyComposer = el.querySelector(".reply-composer") as HTMLElement;
      const replyInput = el.querySelector(".reply-input") as HTMLTextAreaElement;
      if (replyComposer && replyInput) {
        replyComposer.style.display = "block";
        replyInput.value = savedReply;
      }
    }
  }

  // Restore input
  if (postInputEl) postInputEl.value = savedPostInput;

  // Restore scroll
  postList.scrollTop = scrollTop;
}

// ============================================================================
// SSE Subscription
// ============================================================================

function stopSSE(): void {
  if (sseAbortController) {
    sseAbortController.abort();
    sseAbortController = null;
  }
}

async function subscribeToChannel(
  workspace: string,
  channel: string
): Promise<void> {
  stopSSE();
  postsMap.clear();

  sseAbortController = new AbortController();
  const url = `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/?mode=subscribe`;

  slog.info("Subscribing to channel", ["url", url]);

  try {
    await fetchEventSource(url, {
      headers: {
        Authorization: `Bearer ${authToken}`,
        Accept: "text/event-stream",
      },
      signal: sseAbortController.signal,
      onmessage(event) {
        if (!event.data) return;
        try {
          const data = JSON.parse(event.data) as DocumentResponse;
          if (event.event === "delete") {
            postsMap.delete(data.path);
          } else {
            // "update" or default
            const doc = data.doc as PostDoc;
            if (typeof doc.msg === "string") {
              postsMap.set(data.path, {
                path: data.path,
                doc,
                meta: data.meta,
                depth: 0,
              });
            }
          }
          // Re-render
          renderPostList(Array.from(postsMap.values()));
        } catch (e) {
          slog.warn("SSE parse error", ["error", e]);
        }
      },
      onerror(err) {
        slog.warn("SSE error", ["error", err]);
        // Don't retry on abort
        if (sseAbortController?.signal.aborted) {
          throw err;
        }
      },
    });
  } catch (e) {
    if (!sseAbortController?.signal.aborted) {
      slog.warn("SSE connection error", ["error", e]);
    }
  }
}

// ============================================================================
// Load Posts (fallback/initial)
// ============================================================================

async function loadPosts(workspace: string, channel: string): Promise<void> {
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(workspace)}/channels/${encodeURIComponent(channel)}/posts/`
  );
  if (!resp.ok) {
    if (resp.status === 404) {
      showNotification("Error: Posts collection not found");
    }
    return;
  }
  const docs = (await resp.json()) as DocumentResponse[];
  postsMap.clear();
  for (const docResp of docs) {
    const doc = docResp.doc as PostDoc;
    if (typeof doc.msg === "string") {
      postsMap.set(docResp.path, {
        path: docResp.path,
        doc,
        meta: docResp.meta,
        depth: 0,
      });
    }
  }
  renderPostList(Array.from(postsMap.values()));
}

// ============================================================================
// UI: Workspace List
// ============================================================================

function renderWorkspaceList(workspaces: DocumentResponse[]): void {
  const list = document.getElementById("workspace-list")!;
  list.innerHTML = "";
  for (const ws of workspaces) {
    const name = getNameFromPath(ws.path);
    const li = document.createElement("li");
    li.className = "item-list-item";
    li.textContent = name;
    li.addEventListener("click", () => {
      openWorkspace(name);
    });
    list.appendChild(li);
  }
}

function renderChannelList(channels: DocumentResponse[]): void {
  const list = document.getElementById("channel-list")!;
  list.innerHTML = "";
  for (const ch of channels) {
    const name = getNameFromPath(ch.path);
    const li = document.createElement("li");
    li.className = "item-list-item";
    li.textContent = name;
    li.addEventListener("click", () => {
      openChannel(name);
    });
    list.appendChild(li);
  }
}

// ============================================================================
// UI Actions
// ============================================================================

async function openWorkspace(name: string): Promise<void> {
  // Fetch channels to verify workspace exists
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(name)}/channels/`
  );
  if (!resp.ok) {
    if (resp.status === 404) {
      showNotification(`Error: Workspace "${name}" not found`);
    } else {
      const err = await resp.text();
      showNotification(`Error opening workspace: ${err}`);
    }
    return;
  }

  currentWorkspace = name;
  currentChannel = null;
  stopSSE();
  postsMap.clear();

  // Update UI
  document.getElementById("current-workspace-name")!.textContent = name;
  document.getElementById("current-channel-name")!.textContent =
    "Select a channel";
  document.getElementById("post-list")!.innerHTML = "";

  const channels = (await resp.json()) as DocumentResponse[];
  renderChannelList(channels);
}

async function openChannel(name: string): Promise<void> {
  if (!currentWorkspace) {
    showNotification("Error: No workspace selected");
    return;
  }

  // Verify channel exists by trying to get its posts collection
  const resp = await apiFetch(
    `${DB_HOST}${DB_PATH}${encodeURIComponent(currentWorkspace)}/channels/${encodeURIComponent(name)}/posts/`
  );
  if (!resp.ok) {
    if (resp.status === 404) {
      showNotification(`Error: Channel "${name}" not found`);
    } else {
      showNotification(`Error: Could not open channel "${name}"`);
    }
    return;
  }

  currentChannel = name;

  // Update UI
  document.getElementById("current-channel-name")!.textContent = name;

  // Subscribe to SSE for live updates (also gets initial post list)
  subscribeToChannel(currentWorkspace, name).catch((e) => {
    slog.warn("Subscribe failed, falling back to load", ["error", e]);
    if (currentWorkspace && currentChannel) {
      loadPosts(currentWorkspace, currentChannel);
    }
  });
}

// ============================================================================
// Event Handlers: Login / Logout
// ============================================================================

function handleLogin(): void {
  const input = document.getElementById("username-input") as HTMLInputElement;
  const username = input.value.trim();
  if (!username) {
    showNotification("Please enter a username");
    return;
  }

  apiLogin(username).then((token) => {
    if (token) {
      authToken = token;
      currentUsername = username;
      slog.info("Logged in", ["username", username]);

      // Show app, hide login
      document.getElementById("login-section")!.style.display = "none";
      document.getElementById("app-section")!.style.display = "flex";
      document.getElementById("current-user-display")!.textContent = username;

      // Fetch workspaces
      fetchWorkspaces().then(renderWorkspaceList);
    }
  });
}

function handleLogout(): void {
  apiLogout().then(() => {
    authToken = null;
    currentUsername = null;
    currentWorkspace = null;
    currentChannel = null;
    stopSSE();
    postsMap.clear();

    // Show login, hide app
    document.getElementById("app-section")!.style.display = "none";
    document.getElementById("login-section")!.style.display = "flex";
    document.getElementById("current-user-display")!.textContent = "";
    document.getElementById("workspace-list")!.innerHTML = "";
    document.getElementById("channel-list")!.innerHTML = "";
    document.getElementById("post-list")!.innerHTML = "";
    document.getElementById("current-workspace-name")!.textContent =
      "Select a workspace";
    document.getElementById("current-channel-name")!.textContent =
      "Select a channel";

    // Clear input
    (document.getElementById("username-input") as HTMLInputElement).value = "";
  });
}

// ============================================================================
// Event Handlers: Workspaces
// ============================================================================

function handleOpenWorkspace(): void {
  const input = document.getElementById("workspace-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;
  openWorkspace(name);
}

function handleCreateWorkspace(): void {
  const input = document.getElementById("workspace-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;

  createWorkspace(name).then((success) => {
    if (success) {
      fetchWorkspaces().then(renderWorkspaceList);
      openWorkspace(name);
    }
  });
}

function handleDeleteWorkspace(): void {
  const input = document.getElementById("workspace-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;

  deleteWorkspaceApi(name).then((success) => {
    if (success) {
      // If current workspace was deleted, close it
      if (currentWorkspace === name) {
        currentWorkspace = null;
        currentChannel = null;
        stopSSE();
        postsMap.clear();
        document.getElementById("current-workspace-name")!.textContent =
          "Select a workspace";
        document.getElementById("current-channel-name")!.textContent =
          "Select a channel";
        document.getElementById("post-list")!.innerHTML = "";
        document.getElementById("channel-list")!.innerHTML = "";
      }
      fetchWorkspaces().then(renderWorkspaceList);
    }
  });
}

// ============================================================================
// Event Handlers: Channels
// ============================================================================

function handleOpenChannel(): void {
  const input = document.getElementById("channel-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;
  openChannel(name);
}

function handleCreateChannel(): void {
  if (!currentWorkspace) {
    showNotification("Error: No workspace selected");
    return;
  }
  const input = document.getElementById("channel-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;

  createChannel(currentWorkspace, name).then((success) => {
    if (success) {
      fetchChannels(currentWorkspace!).then(renderChannelList);
      openChannel(name);
    }
  });
}

function handleDeleteChannel(): void {
  if (!currentWorkspace) {
    showNotification("Error: No workspace selected");
    return;
  }
  const input = document.getElementById("channel-input") as HTMLInputElement;
  const name = input.value.trim();
  if (!name) return;

  deleteChannelApi(currentWorkspace, name).then((success) => {
    if (success) {
      // If current channel was deleted, close it
      if (currentChannel === name) {
        currentChannel = null;
        stopSSE();
        postsMap.clear();
        document.getElementById("current-channel-name")!.textContent =
          "Select a channel";
        document.getElementById("post-list")!.innerHTML = "";
      }
      fetchChannels(currentWorkspace!).then(renderChannelList);
    }
  });
}

// ============================================================================
// Event Handlers: Posts
// ============================================================================

function handleSendPost(): void {
  const input = document.getElementById("post-input") as HTMLTextAreaElement;
  const msg = input.value.trim();
  if (!msg || !currentWorkspace || !currentChannel) return;

  createPost(currentWorkspace, currentChannel, msg).then((uri) => {
    if (uri) {
      input.value = "";
      // SSE will update automatically, but also load to ensure consistency
      if (currentWorkspace && currentChannel) {
        loadPosts(currentWorkspace, currentChannel);
      }
    }
  });
}

// ============================================================================
// Initialization
// ============================================================================

function main(): void {
  slog.info("Using database", [
    "database",
    `${DB_HOST}${DB_PATH}`,
  ]);

  // Login/Logout
  document
    .getElementById("login-btn")!
    .addEventListener("click", handleLogin);
  document
    .getElementById("username-input")!
    .addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") handleLogin();
    });
  document
    .getElementById("logout-btn")!
    .addEventListener("click", handleLogout);

  // Notification close
  document
    .getElementById("close-notification")!
    .addEventListener("click", hideNotification);

  // Workspace actions
  document
    .getElementById("open-workspace-btn")!
    .addEventListener("click", handleOpenWorkspace);
  document
    .getElementById("workspace-input")!
    .addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") handleOpenWorkspace();
    });
  document
    .getElementById("create-workspace-btn")!
    .addEventListener("click", handleCreateWorkspace);
  document
    .getElementById("delete-workspace-btn")!
    .addEventListener("click", handleDeleteWorkspace);

  // Channel actions
  document
    .getElementById("open-channel-btn")!
    .addEventListener("click", handleOpenChannel);
  document
    .getElementById("channel-input")!
    .addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter") handleOpenChannel();
    });
  document
    .getElementById("create-channel-btn")!
    .addEventListener("click", handleCreateChannel);
  document
    .getElementById("delete-channel-btn")!
    .addEventListener("click", handleDeleteChannel);

  // Post actions
  document
    .getElementById("send-post-btn")!
    .addEventListener("click", handleSendPost);
  document
    .getElementById("post-input")!
    .addEventListener("keydown", (e: KeyboardEvent) => {
      if (e.key === "Enter" && (e.ctrlKey || e.metaKey)) handleSendPost();
    });
}

/* Register event handler to run after the page is fully loaded. */
document.addEventListener("DOMContentLoaded", () => {
  main();
});

