// Normalize a path for comparison: strip leading slash
function normalizePath(p: string): string {
  return p.startsWith("/") ? p.slice(1) : p;
}

function buildPostTree(posts: PostRecord[]): PostRecord[] {
  // Sort all posts by createdAt
  const sortedPosts = [...posts].sort(
    (a, b) => a.meta.createdAt - b.meta.createdAt
  );

  // Build children map: normalized parent path Ôćĺ children
  // Parent paths may or may not have a leading slash depending on source
  const childrenMap = new Map<string, PostRecord[]>();
  const rootPosts: PostRecord[] = [];

  for (const post of sortedPosts) {
    const parent = normalizePath(post.doc.parent || "");
    if (!parent) {
      rootPosts.push(post);
    } else {
      if (!childrenMap.has(parent)) {
        childrenMap.set(parent, []);
      }
      childrenMap.get(parent)!.push(post);
    }
  }

  // DFS traversal to build ordered list with depths
  const result: PostRecord[] = [];

  function dfs(post: PostRecord, depth: number): void {
    result.push({ ...post, depth });
    // Normalize post.path for lookup since parent keys are normalized
    const children = childrenMap.get(normalizePath(post.path)) || [];
    // Children already sorted since we sorted all posts
    for (const child of children) {
      dfs(child, depth + 1);
    }
  }

  for (const root of rootPosts) {
    dfs(root, 0);
  }

  return result;
}

